class Game2048 {
  constructor(board, spawnQueue) {
    // Deep copy the board to avoid aliasing
    this._board = board.map(row => [...row]);
    this._spawnQueue = [...spawnQueue]; // Copy the queue so we can consume from it
    this._score = 0;
  }

  get board() {
    return this._board.map(row => [...row]);
  }

  get score() {
    return this._score;
  }

  get gameOver() {
    // Check for empty cells
    for (let r = 0; r < 4; r++) {
      for (let c = 0; c < 4; c++) {
        if (this._board[r][c] === 0) return false;
      }
    }

    // Check for adjacent equal tiles horizontally or vertically
    for (let r = 0; r < 4; r++) {
      for (let c = 0; c < 4; c++) {
        const val = this._board[r][c];
        // Check right neighbor
        if (c + 1 < 4 && this._board[r][c + 1] === val) return false;
        // Check down neighbor
        if (r + 1 < 4 && this._board[r + 1][c] === val) return false;
      }
    }

    return true;
  }

  move(dir) {
    const oldBoard = this._board.map(row => [...row]);
    let changed = false;

    // Process each line based on direction
    if (dir === "left" || dir === "right") {
      for (let r = 0; r < 4; r++) {
        let row = [...this._board[r]];
        if (dir === "right") row.reverse();

        const merged = this._slideAndMerge(row);

        if (dir === "right") merged.reverse();

        // Check if changed
        for (let c = 0; c < 4; c++) {
          if (this._board[r][c] !== merged[c]) {
            changed = true;
          }
        }

        this._board[r] = merged;
      }
    } else { // up or down
      for (let c = 0; c < 4; c++) {
        let col = [];
        for (let r = 0; r < 4; r++) {
          col.push(this._board[r][c]);
        }

        if (dir === "down") col.reverse();

        const merged = this._slideAndMerge(col);

        if (dir === "down") merged.reverse();

        // Check if changed
        for (let r = 0; r < 4; r++) {
          if (this._board[r][c] !== merged[r]) {
            changed = true;
          }
        }

        for (let r = 0; r < 4; r++) {
          this._board[r][c] = merged[r];
        }
      }
    }

    if (changed) {
      // Consume next spawn
      if (this._spawnQueue.length > 0) {
        const spawn = this._spawnQueue.shift();
        this._board[spawn.r][spawn.c] = spawn.v;
      }
      return true;
    } else {
      return false;
    }
  }

  _slideAndMerge(line) {
    // Remove zeros first
    let tiles = line.filter(v => v !== 0);

    // Merge adjacent equal values from the start (direction of travel)
    const merged = [];
    let i = 0;
    while (i < tiles.length) {
      if (i + 1 < tiles.length && tiles[i] === tiles[i + 1]) {
        const newVal = tiles[i] * 2;
        this._score += newVal;
        merged.push(newVal);
        i += 2; // Skip both tiles since they merged
      } else {
        merged.push(tiles[i]);
        i++;
      }
    }

    // Pad with zeros to length 4
    while (merged.length < 4) {
      merged.push(0);
    }

    return merged;
  }
}
