class Game2048 {
    /**
     * @param {number[][]} board - The initial 4x4 grid.
     * @param {{r: number, c: number, v: number}[]} spawnQueue - Instructions for tile spawning.
     */
    constructor(board, spawnQueue) {
        // Deep copy the board
        this._board = board.map(row => [...row]);
        this._spawnQueue = [...spawnQueue];
        this._score = 0;
    }

    /**
     * Helper function to process a single 1D line (row or column) for sliding and merging.
     * @param {number[]} line - The 1D array to process.
     * @param {string} direction - "left" or "right" (relative to the line).
     * @returns {{newLine: number[], scoreGained: number, changed: boolean}}
     */
    _processLine(line, direction) {
        const N = 4;
        let scoreGained = 0;
        let changed = false;

        // 1. Filter non-zero elements
        let filtered = line.filter(val => val !== 0);

        // 2. Merge
        let merged = [];
        let i = 0;
        while (i < filtered.length) {
            const current = filtered[i];
            if (i + 1 < filtered.length && current === filtered[i + 1]) {
                // Merge occurs
                const mergedValue = current * 2;
                merged.push(mergedValue);
                scoreGained += mergedValue;
                i += 2; // Skip the next element as it was merged
            } else {
                merged.push(current);
                i += 1;
            }
        }

        // 3. Pad with zeros
        let newLine = new Array(N).fill(0);

        if (direction === "left") {
            // Place merged tiles starting from index 0
            for (let j = 0; j < merged.length; j++) {
                newLine[j] = merged[j];
            }
        } else { // direction === "right"
            // Place merged tiles starting from index N-1
            for (let j = 0; j < merged.length; j++) {
                newLine[N - 1 - j] = merged[j];
            }
        }

        // Check if the line actually changed
        for (let j = 0; j < N; j++) {
            if (line[j] !== newLine[j]) {
                changed = true;
                break;
            }
        }

        return { newLine, scoreGained, changed };
    }

    /**
     * Moves tiles in the specified direction.
     * @param {"left" | "right" | "up" | "down"} dir
     * @returns {boolean} True if the board changed, false otherwise.
     */
    move(dir) {
        const originalBoard = this._board.map(row => [...row]);
        let boardChanged = false;
        let totalScoreGained = 0;
        let newBoard = this._board.map(row => [...row]);

        if (dir === "left" || dir === "right") {
            // Horizontal movement (process rows)
            for (let r = 0; r < 4; r++) {
                const row = this._board[r];
                const { newLine, scoreGained, changed } = this._processLine(row, dir);

                if (changed) {
                    boardChanged = true;
                    totalScoreGained += scoreGained;
                    newBoard[r] = newLine;
                }
            }
        } else {
            // Vertical movement (process columns)
            for (let c = 0; c < 4; c++) {
                // Extract column
                let column = [];
                for (let r = 0; r < 4; r++) {
                    column.push(this._board[r][c]);
                }

                // Process column (direction is relative to the column)
                const { newLine: newColumn, scoreGained, changed } = this._processLine(column, dir);

                if (changed) {
                    boardChanged = true;
                    totalScoreGained += scoreGained;

                    // Update column in the new board
                    for (let r = 0; r < 4; r++) {
                        newBoard[r][c] = newColumn[r];
                    }
                }
            }
        }

        // Apply changes if any occurred
        if (boardChanged) {
            this._board = newBoard;
            this._score += totalScoreGained;

            // Consume spawn
            if (this._spawnQueue.length > 0) {
                const spawn = this._spawnQueue.shift();
                this._board[spawn.r][spawn.c] = spawn.v;
            }
            return true;
        }

        return false;
    }

    get board() {
        return this._board;
    }

    get score() {
        return this._score;
    }

    get gameOver() {
        // 1. Check for empty cells
        let hasEmpty = false;
        for (let r = 0; r < 4; r++) {
            for (let c = 0; c < 4; c++) {
                if (this._board[r][c] === 0) {
                    hasEmpty = true;
                    break;
                }
            }
            if (hasEmpty) break;
        }

        if (hasEmpty) {
            return false;
        }

        // 2. Check for adjacent equal tiles (no possible moves)
        // Check horizontal adjacency
        for (let r = 0; r < 4; r++) {
            for (let c = 0; c < 3; c++) {
                if (this._board[r][c] === this._board[r][c + 1]) {
                    return false; // Move possible
                }
            }
        }

        // Check vertical adjacency
        for (let r = 0; r < 3; r++) {
            for (let c = 0; c < 4; c++) {
                if (this._board[r][c] === this._board[r + 1][c]) {
                    return false; // Move possible
                }
            }
        }

        // No empty cells AND no adjacent equal tiles means game over
        return true;
    }
