        // If any adjacent tiles are equal, a move *could* change the board (merge).
        // If no adjacent tiles are equal, no move can change the board.

        // Check horizontal adjacency
        for (let r = 0; r < 4; r++) {
            for (let c = 0; c < 3; c++) {
                if (this._board[r][c] === this._board[r][c + 1]) {
                    return false; // Merge possible
                }
            }
        }

        // Check vertical adjacency
        for (let r = 0; r < 3; r++) {
            for (let c = 0; c < 4; c++) {
                if (this._board[r][c] === this._board[r + 1][c]) {
                    return false; // Merge possible
                }
            }
        }

        // Full board, no adjacent merges possible
        return true;
    }

