        this._board = newBoard;
        this._score += totalScoreChange;

        if (boardChanged) {
            // Consume spawn
            if (this._spawnIndex < this._spawnQueue.length) {
                const spawn = this._spawnQueue[this._spawnIndex];
                this._board[spawn.r][spawn.c] = spawn.v;
