    const board = this._board;
    // any empty cell?
    for (let r = 0; r < 4; r++) {
      for (let c = 0; c < 4; c++) {
        if (board[r][c] === 0) return false;
      }
    }
    // any adjacent equal horizontally or vertically?
    for (let r = 0; r < 4; r++) {
      for (let c = 0; c < 4; c++) {
        if (board[r][c] === board[r][c + 1]) return false;
        if (board[r][c] === board[r + 1][c]) return false;
      }
    }
    return true;
  }

  move(dir) {
    const prevBoard = this._board.slice();
    let changed = false;

    const processRow = (row, dir) => {
      const arr = row.slice();
      // compress
      let i = 0;
      while (i < 4 && arr[i] !== 0) i++;
      const compressed = arr.slice(0, i);
      // merge left->right for left/right, right->left for right/left
      if (dir === 'left' || dir === 'up') {
        for (let j = 0; j < compressed.length - 1; j++) {
          if (compressed[j] === compressed[j + 1]) {
            const v = compressed[j] * 2;
            compressed[j] = v;
            compressed[j + 1] = 0;
            this._score += v;
            j++; // skip next element
          }
        }
      } else {
        for (let j = compressed.length - 2; j >= 0; j--) {
          if (compressed[j] === compressed[j + 1]) {
            const v = compressed[j] * 2;
            compressed[j] = v;
            compressed[j + 1] = 0;
            this._score += v;
            j--; // skip previous element
          }
        }
      }
      // fill back to row
      const filled = [...compressed, 0, 0, 0].slice(0, 4);
      const newRow = filled;
      if (newRow.some(v => v !== row[j])) changed = true;
      row = newRow;
    };

    const processCol = (col, dir) => {
      const arr = [];
      for (let r = 0; r < 4; r++) arr.push(this._board[r][col]);
      // compress
      let i = 0;
      while (i < 4 && arr[i] !== 0) i++;
      const compressed = arr.slice(0, i);
      // merge up->down for up/down, down->up for down/up
      if (dir === 'up' || dir === 'left') {
        for (let j = 0; j < compressed.length - 1; j++) {
          if (compressed[j] === compressed[j + 1]) {
            const v = compressed[j] * 2;
